      "type": "codeBlock",
      "content": [
        {
          "type": "text",
          "text": "// Важно: работает только при неотрицательных весах\nfunction dijkstra(graph, start) {\n  const dist = {};\n  const prev = {};\n  const visited = new Set();\n  for (const v in graph) {\n    dist[v] = Infinity;\n    prev[v] = null;\n  }\n  dist[start] = 0;\n\n  // Простейшая очередь с приоритетом (медленная, но компактная)\n  const pq = [{ v: start, d: 0 }];\n  function push(node) { pq.push(node); }\n  function popMin() {\n    let best = 0;\n    for (let i = 1; i < pq.length; i++) {\n      if (pq[i].d < pq[best].d) best = i;\n    }\n    return pq.splice(best, 1)[0];\n  }\n\n  while (pq.length) {\n    const { v: u } = popMin();\n    if (visited.has(u)) continue;\n    visited.add(u);\n\n    for (const { to, w } of graph[u]) {\n      const alt = dist[u] + w;\n      if (alt < dist[to]) {\n        dist[to] = alt;\n        prev[to] = u;\n        push({ v: to, d: alt });\n      }\n    }\n  }\n\n  return { dist, prev };\n}\n\nfunction reconstructPath(prev, target) {\n  const path = [];\n  for (let v = target; v !== null; v = prev[v]) path.push(v);\n  return path.reverse();\n}\n\n// Пример использования\nconst graph = {\n  A: [{ to: 'B', w: 4 }, { to: 'C', w: 2 }],\n  B: [{ to: 'C', w: 5 }, { to: 'D', w: 10 }],\n  C: [{ to: 'E', w: 3 }],\n  D: [{ to: 'F', w: 11 }],\n  E: [{ to: 'D', w: 4 }],\n  F: []\n};\n\nconst { dist, prev } = dijkstra(graph, 'A');\nconsole.log(dist); // кратчайшие расстояния от A до остальных\nconsole.log(reconstructPath(prev, 'D')); // пример пути A -> C -> E -> D"
