          "type": "text",
          "text": "function topoSort(adj) {\n  // Считаем in-degree\n  const inDeg = Object.fromEntries(Object.keys(adj).map(v => [v, 0]));\n  for (const u in adj) for (const v of adj[u]) inDeg[v] = (inDeg[v] ?? 0) + 1;\n\n  // Очередь вершин без входящих рёбер\n  const q = [];\n  for (const v in inDeg) if (inDeg[v] === 0) q.push(v);\n\n  const order = [];\n  while (q.length) {\n    const u = q.shift();\n    order.push(u);\n    for (const v of adj[u]) {\n      inDeg[v]--;\n      if (inDeg[v] === 0) q.push(v);\n    }\n  }\n\n  // Если в порядке меньше вершин, чем в графе — есть цикл\n  const hasCycle = order.length !== Object.keys(adj).length;\n  return { order: hasCycle ? null : order, hasCycle };\n}\n\nconst adj1 = { A:[\"B\",\"C\"], B:[\"D\"], C:[\"D\"], D:[] };\nconsole.log(topoSort(adj1)); // { order: [ 'A', 'B', 'C', 'D' ] (или 'A','C','B','D'), hasCycle: false }\n\nconst adj2 = { A:[\"B\"], B:[\"C\"], C:[\"A\"] }; // цикл A→B→C→A\nconsole.log(topoSort(adj2)); // { order: null, hasCycle: true }"
