{"type":"doc","content":[{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Короткий ответ"}]},{"type":"paragraph","content":[{"type":"text","text":"Граф в памяти обычно хранят как: 1) матрицу смежности (O(V^2), быстрые проверки ребра), 2) список смежности (O(V+E), быстрая итерация по соседям, удобное добавление/удаление), 3) список рёбер (O(E), простая загрузка и хранение), 4) сжатые структуры CSR/CSC для больших разреженных графов. Выбор зависит от плотности графа, требуемых операций (проверка ребра, обход соседей, обновления) и ограничений по памяти."}]},{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Подробный ответ"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Основные способы хранения"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Матрица смежности: двумерный массив V×V. Память O(V^2). Проверка наличия ребра O(1). Итерация по соседям O(V). Хороша для плотных графов и частых проверок ребра."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Список смежности: для каждой вершины список/множество соседей. Память O(V+E). Проверка ребра O(deg(u)) или O(1) с Set. Итерация по соседям O(deg(u)). Лучший выбор для разреженных и динамичных графов."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Список рёбер: массив пар/троек (u, v, w). Память O(E). Удобен для хранения, сериализации и алгоритмов на рёбрах. Проверка ребра O(E) (если не индексировать)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"CSR/CSC: сжатые форматы для разреженных графов. Память близка к O(V+E). Отличная итерация по соседям и cache-friendly обходы. Сложно/дорого обновлять онлайн."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Матрица смежности (Adjacency Matrix)"}]},{"type":"paragraph","content":[{"type":"text","text":"Двумерный массив размера V×V, где элемент matrix[u][v] = 0/1 или вес ребра. Для неориентированного графа матрица симметрична."}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Память: O(V^2). Для больших разреженных графов — неэффективно."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Проверка ребра u→v: O(1). Итерация соседей: O(V)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Добавление вершины: O(V^2) (перевыделение). Добавление ребра: O(1)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Подходит для плотных графов и задач с частыми проверками наличия ребра."}]}]}]},{"type":"codeBlock","content":[{"type":"text","text":"const n = 5; // количество вершин
const matrix = Array.from({ length: n }, () => Array(n).fill(0));

function addEdge(u, v, w = 1, directed = false) {
  matrix[u][v] = w; // 1 или вес
  if (!directed) matrix[v][u] = w;
}

function hasEdge(u, v) {
  return matrix[u][v] !== 0;
}

function neighbors(u) {
  const res = [];
  for (let v = 0; v < n; v++) if (matrix[u][v] !== 0) res.push(v);
  return res;
}

addEdge(0, 1);
addEdge(0, 3);
console.log(hasEdge(0, 1)); // true
console.log(neighbors(0));  // [1, 3]"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Список смежности (Adjacency List)"}]},{"type":"paragraph","content":[{"type":"text","text":"Для каждой вершины храним коллекцию её соседей: массив, Set или Map (для взвешенных графов). Хорошо масштабируется для разреженных графов и поддерживает динамические изменения."}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Память: O(V+E)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Проверка ребра: O(deg(u)) с массивом, O(1) c Set/Map."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Итерация соседей: O(deg(u)). Добавление/удаление ребра: амортизированно O(1)."}]}]}]},{"type":"codeBlock","content":[{"type":"text","text":"// Невзвешенный граф: Map<number, Set<number>>
const g = new Map();

function addVertex(u) {
  if (!g.has(u)) g.set(u, new Set());
}

function addEdge(u, v, directed = false) {
  addVertex(u); addVertex(v);
  g.get(u).add(v);
  if (!directed) g.get(v).add(u);
}

function hasEdge(u, v) {
  return g.has(u) && g.get(u).has(v);
}

function neighbors(u) {
  return g.get(u) ? [...g.get(u)] : [];
}

function removeEdge(u, v, directed = false) {
  if (g.has(u)) g.get(u).delete(v);
  if (!directed && g.has(v)) g.get(v).delete(u);
}

// Пример использования
addEdge(0, 1);
addEdge(0, 2);
console.log(hasEdge(0, 1)); // true
console.log(neighbors(0));  // [1, 2]"}]},{"type":"codeBlock","content":[{"type":"text","text":"// Взвешенный граф: Map<number, Map<number, number>>
const wg = new Map();

function addWeightedEdge(u, v, w, directed = false) {
  if (!wg.has(u)) wg.set(u, new Map());
  if (!wg.has(v)) wg.set(v, new Map());
  wg.get(u).set(v, w);
  if (!directed) wg.get(v).set(u, w);
}

function weight(u, v) {
  return wg.has(u) ? wg.get(u).get(v) : undefined; // undefined = ребра нет
}

addWeightedEdge(1, 3, 2.5);
console.log(weight(1, 3)); // 2.5"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Список рёбер (Edge List)"}]},{"type":"paragraph","content":[{"type":"text","text":"Храним массив рёбер, каждое ребро — пара (u, v) или тройка (u, v, w). Простой формат для обмена данными и некоторых алгоритмов (например, сортировка по весу для Краскала)."}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Память: O(E)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Проверка ребра: O(E), если не строить индексы."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Итерация по соседям требует индексации/группировки."}]}]}]},{"type":"codeBlock","content":[{"type":"text","text":"// Список рёбер: [[u, v, w?]]
const edges = [ [0, 1], [0, 2], [2, 3] ];

// Для быстрых соседей — сгруппируем в список смежности при загрузке
const adj = new Map();
for (const [u, v] of edges) {
  if (!adj.has(u)) adj.set(u, []);
  adj.get(u).push(v);
}
console.log(adj.get(0)); // [1, 2]"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"CSR/CSC (Compressed Sparse Row/Column)"}]},{"type":"paragraph","content":[{"type":"text","text":"Сжатые структуры для разреженных графов (по аналогии с разреженными матрицами). CSR хранит всех соседей вершины подряд в одном массиве и массив смещений для быстрого доступа."}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Память: близко к O(V+E), хорошая локальность в памяти."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Идеально для обходов и вычислений на больших графах. Обновления (добавление/удаление) неудобны — требуется перестройка."}]}]}]},{"type":"codeBlock","content":[{"type":"text","text":"// Построение CSR из списка рёбер
function buildCSR(n, edges, directed = false) {
  const tmp = Array.from({ length: n }, () => []);
  for (const [u, v] of edges) {
    tmp[u].push(v);
    if (!directed) tmp[v].push(u);
  }
  const offsets = new Uint32Array(n + 1);
  let total = 0;
  for (let i = 0; i < n; i++) {
    offsets[i] = total;
    total += tmp[i].length;
  }
  offsets[n] = total;
  const neighbors = new Uint32Array(total);
  let idx = 0;
  for (let i = 0; i < n; i++) {
    for (const v of tmp[i]) neighbors[idx++] = v;
  }
  return { offsets, neighbors };
}

function neighborsCSR(csr, u) {
  const { offsets, neighbors } = csr;
  return neighbors.subarray(offsets[u], offsets[u + 1]);
}

const csr = buildCSR(5, [[0,1],[0,2],[2,3]]);
console.log([...neighborsCSR(csr, 0)]); // [1, 2]"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Матрица инцидентности и другие варианты"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Матрица инцидентности: V×E, полезна для некоторых теоретических/линейно-алгебраических задач. Память O(V·E) — редко используется на практике для больших графов."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Объектная модель (узлы/рёбра как объекты с ссылками): удобно для сложных атрибутов, но дороже по памяти и кэшу."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Сравнение по операциям (усреднённо)"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Память: матрица O(V^2) > список смежности O(V+E) ≈ CSR O(V+E) > список рёбер O(E) (без индексов)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Проверка ребра u→v: матрица O(1), список смежности O(deg(u)) или O(1) при Set/Map, CSR O(log deg(u)) при бинарном поиске (если отсортировано) или O(deg(u))."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Итерация соседей: список смежности/CSR O(deg(u)) — быстрее и кэш-дружелюбнее, матрица O(V)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Обновления: список смежности — дешёвые; матрица — дёшево для рёбер, дорого для вершин; CSR — дорого (перестроение)."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Как выбрать структуру"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Плотный граф (много рёбер) и важна проверка наличия ребра: матрица смежности."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Разреженный граф, частые обходы и обновления: список смежности (Set/Map)."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Очень большой разреженный граф, мало/нет обновлений, важна производительность обхода: CSR/CSC."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Простое хранение/обмен: список рёбер."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Особенности: направленные, взвешенные, мультиграфы"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Направленные: храните только u→v (не дублируйте v→u). В матрице — нессиметричные элементы."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Взвешенные: в матрице — числа весов, в списке смежности — Map<сосед, вес> или массив объектов { to, w }."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Мультиграфы: разрешены кратные рёбра. В списке смежности используйте массив (не Set) или храните счётчик/список рёбер между парой вершин."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Петли (u=u): поддерживаются всеми структурами; в матрице — диагональные элементы."}]}]}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Пример: типичный граф для веб-задач (обходы BFS/DFS)"}]},{"type":"codeBlock","content":[{"type":"text","text":"// Список смежности с Set: удобно и быстро для проверок
const G = new Map();
const dir = false; // неориентированный

function v(u){ if(!G.has(u)) G.set(u, new Set()); }
function add(u,v){ v(u); v(v); G.get(u).add(v); if(!dir) G.get(v).add(u); }

// Построим небольшой граф
add(0,1); add(0,2); add(1,3); add(2,3); add(3,4);

function bfs(start){
  const q = [start], seen = new Set([start]), order = [];
  while(q.length){
    const u = q.shift(); order.push(u);
    for(const v of G.get(u) || []) if(!seen.has(v)){ seen.add(v); q.push(v); }
  }
  return order;
}

function dfs(start){
  const st = [start], seen = new Set(), order = [];
  while(st.length){
    const u = st.pop();
    if(seen.has(u)) continue; seen.add(u); order.push(u);
    for(const v of G.get(u) || []) if(!seen.has(v)) st.push(v);
  }
  return order;
}

console.log('BFS:', bfs(0)); // например, [0,1,2,3,4]
console.log('DFS:', dfs(0));"}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Итоги"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Нет единственно правильного представления: выбирайте под задачи и ограничения."}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"type":"text","text":"Матрица — для плотных и частых проверок ребра; список смежности — универсальный и динамичный выбор; список рёбер — простой формат данных; CSR/CSC — для больших разреженных графов и высокопроизводительных обходов."}]}]}]}]}

