    {
      "type": "codeBlock",
      "attrs": { "language": "javascript" },
      "text": "const vertices = ['A', 'B', 'C', 'D'];\nconst edges = [\n  // формат: [u, v] для невзвешенного; [u, v, w] для взвешенного\n  ['A', 'B'],\n  ['A', 'D'],\n  ['B', 'C'],\n];\n\nfunction buildAdjMatrix(vertices, edges, { directed = false, weighted = false } = {}) {\n  const n = vertices.length;\n  const index = new Map(vertices.map((v, i) => [v, i]));\n  const noEdge = weighted ? null : 0;\n  const M = Array.from({ length: n }, () => Array(n).fill(noEdge));\n\n  for (const e of edges) {\n    const [u, v, w] = e;\n    const i = index.get(u);\n    const j = index.get(v);\n    if (i === undefined || j === undefined) throw new Error('Unknown vertex');\n\n    if (weighted) {\n      M[i][j] = w;\n      if (!directed) M[j][i] = w;\n    } else {\n      M[i][j] = 1;\n      if (!directed) M[j][i] = 1;\n    }\n  }\n\n  return { M, index, noEdge };\n}\n\nconst { M, index, noEdge } = buildAdjMatrix(vertices, edges, { directed: false, weighted: false });\nconsole.log(M);\n\nfunction hasEdge(M, i, j, noEdge) {\n  return M[i][j] !== noEdge;\n}\n\nconsole.log('A-B?', hasEdge(M, index.get('A'), index.get('B'), noEdge)); // true\nconsole.log('C-D?', hasEdge(M, index.get('C'), index.get('D'), noEdge)); // false"
    },
    {
      "type": "heading",
