    {
      "type": "codeBlock",
      "attrs": { "language": "python" },
      "text": "from typing import List, Dict, Tuple, Any\n\nvertices = ['A', 'B', 'C', 'D']\nedges: List[Tuple[str, str]] = [\n    ('A', 'B'),\n    ('A', 'D'),\n    ('B', 'C'),\n]\n\ndef build_adj_matrix(vertices: List[str], edges: List[Tuple], directed: bool = False, weighted: bool = False):\n    n = len(vertices)\n    index: Dict[str, int] = {v: i for i, v in enumerate(vertices)}\n    no_edge: Any = None if weighted else 0\n    M: List[List[Any]] = [[no_edge for _ in range(n)] for _ in range(n)]\n\n    for e in edges:\n        if weighted:\n            u, v, w = e\n        else:\n            u, v = e\n            w = 1\n        i, j = index[u], index[v]\n        M[i][j] = w\n        if not directed:\n            M[j][i] = w\n\n    return M, index, no_edge\n\nM, index, no_edge = build_adj_matrix(vertices, edges, directed=False, weighted=False)\nprint(M)\n\ndef has_edge(M: List[List[Any]], i: int, j: int, no_edge: Any) -> bool:\n    return M[i][j] != no_edge\n\nprint('A-B?', has_edge(M, index['A'], index['B'], no_edge))  # True\nprint('C-D?', has_edge(M, index['C'], index['D'], no_edge))  # False"
