        {
          "type": "text",
          "text": "type Graph = Record<string, string[]>;\n\nfunction bfs(graph: Graph, start: string) {\n  const dist: Record<string, number> = {};\n  const parent: Record<string, string | null> = {};\n\n  for (const v in graph) {\n    dist[v] = Infinity;\n    parent[v] = null;\n  }\n\n  const queue: string[] = [];\n  let head = 0; // указатель на голову очереди для O(1) dequeue\n\n  dist[start] = 0;\n  queue.push(start);\n\n  while (head < queue.length) {\n    const u = queue[head++];\n    for (const w of graph[u]) {\n      if (dist[w] === Infinity) { // не посещён\n        dist[w] = dist[u] + 1;\n        parent[w] = u;\n        queue.push(w);\n      }\n    }\n  }\n\n  return { dist, parent };\n}\n\nfunction reconstructPath(parent: Record<string, string | null>, target: string) {\n  const path: string[] = [];\n  let cur: string | null = target;\n  while (cur !== null) {\n    path.push(cur);\n    cur = parent[cur];\n  }\n  path.reverse();\n  return path;\n}\n\n// Пример использования\nconst graph: Graph = {\n  A: [\"B\", \"C\"],\n  B: [\"A\", \"D\", \"E\"],\n  C: [\"A\", \"F\"],\n  D: [\"B\"],\n  E: [\"B\", \"F\"],\n  F: [\"C\", \"E\"],\n};\n\nconst { dist, parent } = bfs(graph, \"A\");\nconsole.log(dist[\"F\"]); // 2 — кратчайшее число рёбер A->F\nconsole.log(reconstructPath(parent, \"F\")); // Например: [ 'A', 'C', 'F' ] (один из кратчайших путей)"
