      "content": [{ "type": "text", "text": "Где применяется" }]
    },
    {
      "type": "bulletList",
      "content": [
        { "type": "listItem", "content": [{ "type": "paragraph", "content": [{ "type": "text", "text": "Проверка связности графа / подсчёт компонент связности" }] }] },
        { "type": "listItem", "content": [{ "type": "paragraph", "content": [{ "type": "text", "text": "Нахождение путей и предков (для восстановления маршрутов)" }] }] },
        { "type": "listItem", "content": [{ "type": "paragraph", "content": [{ "type": "text", "text": "Обнаружение циклов (и в направленных, и в ненаправленных графах)" }] }] },
        { "type": "listItem", "content": [{ "type": "paragraph", "content": [{ "type": "text", "text": "Топологическая сортировка в DAG (направленный ацикличный граф)" }] }] },
        { "type": "listItem", "content": [{ "type": "paragraph", "content": [{ "type": "text", "text": "Поиск точек сочленения и мостов, компонент сильной связности (с модификациями)" }] }] }
