          ]
        },
        {
          "type": "listItem",
          "content": [
            { "type": "paragraph", "content": [{ "type": "text", "text": "Для задач маршрутизации по кратчайшему числу рёбер используйте BFS, а не DFS." }] }
          ]
        }
      ]
