    {
      "type": "codeBlock",
      "content": [
        {
          "type": "text",
          "text": "/*\n  n — число вершин (0..n-1)\n  edges — массив пар [u, v] для рёбер u→v\n  Возвращает { order, unique } или кидает ошибку при наличии цикла\n*/\nfunction topoSortKahn(n, edges) {\n  const adj = Array.from({ length: n }, () => []);\n  const indeg = Array(n).fill(0);\n  for (const [u, v] of edges) {\n    adj[u].push(v);\n    indeg[v]++;\n  }\n\n  const queue = [];\n  for (let i = 0; i < n; i++) if (indeg[i] === 0) queue.push(i);\n\n  const order = [];\n  let unique = true; // будет ложным, если на каком-то шаге есть выбор из >1 вершины\n\n  while (queue.length) {\n    if (queue.length > 1) unique = false;\n    // Можно отсортировать queue для детерминизма, но это меняет только вид порядка, не корректность\n    const u = queue.shift();\n    order.push(u);\n    for (const v of adj[u]) {\n      indeg[v]--;\n      if (indeg[v] === 0) queue.push(v);\n    }\n  }\n\n  if (order.length !== n) {\n    throw new Error(\"Граф содержит цикл: топологическая сортировка невозможна\");\n  }\n\n  return { order, unique };\n}\n\n// Пример использования:\nconst n = 5;\nconst edges = [ [0,2], [1,2], [1,3], [3,4] ];\nconst result = topoSortKahn(n, edges);\nconsole.log(result.order);  // Например: [1,0,3,4,2]\nconsole.log(result.unique); // false — на шагах был выбор\n"
        }
      ]
    },
    {
      "type": "heading",
      "attrs": { "level": 3 },
