    {
      "type": "codeBlock",
      "content": [
        {
          "type": "text",
          "text": "from typing import List, Tuple\n\n# n — число вершин (0..n-1)\n# edges — список рёбер (u, v) для u→v\n# Возвращает список вершин в топологическом порядке\n\ndef topo_sort_dfs(n: int, edges: List[Tuple[int, int]]) -> List[int]:\n    adj = [[] for _ in range(n)]\n    for u, v in edges:\n        adj[u].append(v)\n\n    WHITE, GRAY, BLACK = 0, 1, 2\n    color = [WHITE] * n\n    order = []\n\n    def dfs(u: int):\n        color[u] = GRAY\n        for v in adj[u]:\n            if color[v] == GRAY:\n                raise ValueError(\"Граф содержит цикл: топологическая сортировка невозможна\")\n            if color[v] == WHITE:\n                dfs(v)\n        color[u] = BLACK\n        order.append(u)  # обратный постпорядок\n\n    for u in range(n):\n        if color[u] == WHITE:\n            dfs(u)\n\n    order.reverse()\n    return order\n\n# Пример использования\nn = 5\nedges = [(0, 2), (1, 2), (1, 3), (3, 4)]\nprint(topo_sort_dfs(n, edges))  # Например: [1, 0, 3, 4, 2]\n"
        }
