        {
          "type": "text",
          "text": "const INF = Infinity;\n\nfunction floydWarshall(adj) {\n  const n = adj.length;\n  const dist = Array.from({ length: n }, (_, i) => Array.from({ length: n }, (_, j) => adj[i][j]));\n  const next = Array.from({ length: n }, () => Array(n).fill(null));\n\n  // Инициализация\n  for (let i = 0; i < n; i++) {\n    for (let j = 0; j < n; j++) {\n      if (i === j && dist[i][j] !== 0) dist[i][j] = 0;\n      if (i !== j && dist[i][j] !== INF) next[i][j] = j;\n    }\n  }\n\n  // Основные тройные циклы\n  for (let k = 0; k < n; k++) {\n    for (let i = 0; i < n; i++) {\n      const dik = dist[i][k];\n      if (dik === INF) continue;\n      for (let j = 0; j < n; j++) {\n        const dkj = dist[k][j];\n        if (dkj === INF) continue;\n        const alt = dik + dkj;\n        if (alt < dist[i][j]) {\n          dist[i][j] = alt;\n          next[i][j] = next[i][k];\n        }\n      }\n    }\n  }\n\n  // Обнаружение отрицательных циклов\n  let hasNegativeCycle = false;\n  const negativeCycleVertices = [];\n  for (let v = 0; v < n; v++) {\n    if (dist[v][v] < 0) {\n      hasNegativeCycle = true;\n      negativeCycleVertices.push(v);\n    }\n  }\n\n  function reconstructPath(u, v) {\n    if (next[u][v] == null) return null; // пути нет\n    const path = [u];\n    while (u !== v) {\n      u = next[u][v];\n      if (u == null) return null; // защита от несогласованных данных\n      path.push(u);\n    }\n    return path;\n  }\n\n  return { dist, next, hasNegativeCycle, negativeCycleVertices, reconstructPath };\n}\n\n// Пример использования\n// Вершины: 0,1,2,3\n// Рёбра: 0→1(3), 0→2(8), 1→2(2), 1→3(5), 2→3(1), 3→1(-2)\nconst adj = [\n  [0,   3,   8,   INF],\n  [INF, 0,   2,   5   ],\n  [INF, INF, 0,   1   ],\n  [INF,-2,   INF, 0   ],\n];\n\nconst { dist, reconstructPath, hasNegativeCycle } = floydWarshall(adj);\nconsole.log('hasNegativeCycle:', hasNegativeCycle); // false\nconsole.log('dist matrix:');\nconsole.table(dist);\n\nconst path03 = reconstructPath(0, 3); // ожидаемо: [0,1,2,3]\nconsole.log('path 0→3:', path03);\n"
        }
